%[text] # 例6.6（チェビシェフ近似）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example06_06"; % mfilename

%imgname = "msipimg01";
%imgname = "msipimg07";
%imgfmt = "tiff";

close all
iFig = 1;
%%
close all
iFig = 1;
%%
%[text] ## パラメータ設定
%K = 4;
M = 8; 
%Delta = 2/M;
R = [-1 1]; % サポート領域
%%
%[text] ## チェビシェフ節点
chebyshev_nodes = cos( (2*(0:M-1)'+1)*pi / (2*M) );
qk = chebyshev_nodes;
%%
%[text] ## チェビシェフ多項式 $\\tau\_m(\\cdot)$ の構成
taum = cell(M,1);

for m=0:M-1
    taum{m+1} = @(q) fcn_cheb(q,m);
end
%%
%[text] ## $\\tau\_m(\\cdot)$ のプロット
hfig = figure(iFig); %[output:07727bbc]

for m=0:M-1
    subplot(M,1,m+1) %[output:07727bbc]
    fplot(@(x) taum{m+1}(x),R,'k','LineWidth',2)
    axis([-1.1 1.1 -1.1 1.1])
    ylabel("$\tau_"+num2str(m)+"(q)$",'Interpreter','latex')
    ax = gca;
    ax.FontSize = 14;
    if m==M-1
        xlabel('$q$','Interpreter','latex')
    else
        ax.XTickLabel = {};
    end
    grid on
end
figWidth = 400; % 幅（ピクセル）
figHeight = 600; % 高さ（ピクセル）
set(hfig, 'Units', 'pixels', 'Position', [100 100 figWidth figHeight]); %[output:07727bbc]

exportgraphics(hfig,fullfile(resfolder,"fig06-04a.png")) %[output:07727bbc]
iFig = iFig + 1;
%%
%[text] ## ガウス関数 $u(q)$
%sigma = 1/2;   % ガウスの標準偏差
u = @(q) q/2 +exp(- (2*q.^2) ); %/ (2*sigma^2) );

%%
%[text] ## ガウス節点上の標本 $x\[n\]$
qn = zeros(M,1);
xn = zeros(M,1);
for n=0:M-1
    qn(n+1) = cos((2*n+1)*pi/(2*M));
    xn(n+1) = u(qn(n+1));
end
ym = dct(xn);
%%
%[text] ## チェビシェフ近似
uhat = @(x) 0;
for m=0:M-1
    if m==0
        alpham = 1/sqrt(M);
    else
        alpham = sqrt(2/M);
    end
    uhat = @(x) uhat(x) + alpham*ym(m+1)*taum{m+1}(x);
end
%%
%[text] ## プロット
hfig = figure(iFig); %[output:7f6dcde4]
subplot(5,1,1) %[output:7f6dcde4]
fplot(@(x) u(x),R,'k','LineWidth',2) %[output:7f6dcde4]
axis([-1.1 1.1 -1.1 1.1]) %[output:7f6dcde4]
ylabel("$u(q)$",'Interpreter','latex') %[output:7f6dcde4]
xlabel('$q$','Interpreter','latex') %[output:7f6dcde4]
ax = gca;
ax.FontSize = 14; %[output:7f6dcde4]
grid on %[output:7f6dcde4]

hold on %[output:7f6dcde4]
stem(qn,xn,'filled','Color',[0.5 0.5 0.5]) %[output:7f6dcde4]

subplot(5,1,2) %[output:7f6dcde4]
stem(0:M-1,xn,'filled','Color',[0.5 0.5 0.5]) %[output:7f6dcde4]
ylabel("$x^{\#}[n]$",'Interpreter','latex') %[output:7f6dcde4]
xlabel('$n$','Interpreter','latex') %[output:7f6dcde4]
ax = gca;
ax.YLim = [-1.4 1.4]; %[output:7f6dcde4]
ax.FontSize = 14; %[output:7f6dcde4]

subplot(5,1,3) %[output:7f6dcde4]
stem(0:M-1,ym,'filled','Color',[0.5 0.5 0.5]) %[output:7f6dcde4]
ylabel("$y^{\#}[m]$",'Interpreter','latex') %[output:7f6dcde4]
xlabel('$m$','Interpreter','latex') %[output:7f6dcde4]
ax = gca;
ax.YLim = [-1.4 1.4]; %[output:7f6dcde4]
ax.FontSize = 14; %[output:7f6dcde4]

subplot(5,1,4) %[output:7f6dcde4]
fplot(@(x) uhat(x),R,'k','LineWidth',2) %[output:7f6dcde4]
axis([-1.1 1.1 -1.1 1.1]) %[output:7f6dcde4]
ylabel("$\check{u}(q)$",'Interpreter','latex') %[output:7f6dcde4]
xlabel('$q$','Interpreter','latex') %[output:7f6dcde4]
ax = gca;
ax.FontSize = 14; %[output:7f6dcde4]
grid on %[output:7f6dcde4]

subplot(5,1,5) %[output:7f6dcde4]
fplot(@(x) u(x)-uhat(x),R,'k','LineWidth',2) %[output:7f6dcde4]
axis([-1.1 1.1 -0.01 0.01]) %[output:7f6dcde4]
ylabel("$u(q)-\check{u}(q)$",'Interpreter','latex') %[output:7f6dcde4]
xlabel('$q$','Interpreter','latex') %[output:7f6dcde4]
ax = gca;
ax.FontSize = 14; %[output:7f6dcde4]
grid on %[output:7f6dcde4]

figWidth = 400; % 幅（ピクセル）
figHeight = 600; % 高さ（ピクセル）
set(hfig, 'Units', 'pixels', 'Position', [100 100 figWidth figHeight]); %[output:7f6dcde4]
exportgraphics(hfig,fullfile(resfolder,"fig06-04b.png")) %[output:7f6dcde4]


iFig = iFig + 1;
%[text] ## 
%%
%[text] ## 補間核の定義
function y = fcn_cheb(x,n)
    alpha = 1;
    %if n==0 
    %    alpha = 1/sqrt(pi);
    %else
    %    alpha = sqrt(2/pi);
    %end
    y = alpha*cos(n*acos(x));
end
